import { Popover as PopoverPrimitive, usePopover, usePopoverContext } from '@ark-ui/react/popover';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import { CloseButton } from '../close-button';
import styles from './Popover.module.css';

const DEFAULT_CLOSE_BUTTON_LABEL = 'Close popover';

type PopoverRootProps = ComponentProps<typeof PopoverPrimitive.Root> & OverlayPortalProps;
type PopoverRootProviderProps = ComponentProps<typeof PopoverPrimitive.RootProvider> &
  OverlayPortalProps;

function PopoverRoot({ portalled, portalRef, ...props }: PopoverRootProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <PopoverPrimitive.Root portalled={portalled} {...props} />
    </OverlayPortalProvider>
  );
}

function PopoverRootProvider({ portalled, portalRef, value, ...props }: PopoverRootProviderProps) {
  return (
    <OverlayPortalProvider portalled={portalled ?? value.portalled} portalRef={portalRef}>
      <PopoverPrimitive.RootProvider value={value} {...props} />
    </OverlayPortalProvider>
  );
}

const PopoverAnchor = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Anchor>,
  ComponentProps<typeof PopoverPrimitive.Anchor>
>(function PopoverAnchor({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Anchor
      ref={ref}
      data-slot="popover-anchor"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const PopoverTrigger = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Trigger>,
  ComponentProps<typeof PopoverPrimitive.Trigger>
>(function PopoverTrigger({ asChild, className, ...props }, ref) {
  return (
    <PopoverPrimitive.Trigger
      ref={ref}
      data-slot="popover-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverIndicator = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Indicator>,
  ComponentProps<typeof PopoverPrimitive.Indicator>
>(function PopoverIndicator({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Indicator
      ref={ref}
      data-slot="popover-indicator"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const PopoverPositioner = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Positioner>,
  ComponentProps<typeof PopoverPrimitive.Positioner>
>(function PopoverPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <PopoverPrimitive.Positioner
        ref={ref}
        data-slot="popover-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const PopoverContent = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Content>,
  ComponentProps<typeof PopoverPrimitive.Content>
>(function PopoverContent({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Content
      ref={ref}
      data-slot="popover-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverArrow = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Arrow>,
  ComponentProps<typeof PopoverPrimitive.Arrow>
>(function PopoverArrow({ className, children, ...props }, ref) {
  return (
    <PopoverPrimitive.Arrow
      ref={ref}
      data-slot="popover-arrow"
      className={clsx(styles.arrow, normalizeClassName(className))}
      {...props}
    >
      {children ?? <PopoverArrowTip />}
    </PopoverPrimitive.Arrow>
  );
});

const PopoverArrowTip = forwardRef<
  ComponentRef<typeof PopoverPrimitive.ArrowTip>,
  ComponentProps<typeof PopoverPrimitive.ArrowTip>
>(function PopoverArrowTip({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.ArrowTip
      ref={ref}
      data-slot="popover-arrow-tip"
      className={clsx(styles.arrowTip, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverTitle = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Title>,
  ComponentProps<typeof PopoverPrimitive.Title>
>(function PopoverTitle({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Title
      ref={ref}
      data-slot="popover-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverDescription = forwardRef<
  ComponentRef<typeof PopoverPrimitive.Description>,
  ComponentProps<typeof PopoverPrimitive.Description>
>(function PopoverDescription({ className, ...props }, ref) {
  return (
    <PopoverPrimitive.Description
      ref={ref}
      data-slot="popover-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverCloseTrigger = forwardRef<
  ComponentRef<typeof PopoverPrimitive.CloseTrigger>,
  ComponentProps<typeof PopoverPrimitive.CloseTrigger>
>(function PopoverCloseTrigger({ asChild, className, ...props }, ref) {
  return (
    <PopoverPrimitive.CloseTrigger
      ref={ref}
      data-slot="popover-close-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.closeTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const PopoverCloseIcon = forwardRef<
  ComponentRef<typeof CloseButton.Root>,
  Omit<ComponentProps<typeof PopoverPrimitive.CloseTrigger>, 'asChild'>
>(function PopoverCloseIcon(
  { className, children, 'aria-label': ariaLabel = DEFAULT_CLOSE_BUTTON_LABEL, ...props },
  ref,
) {
  return (
    <PopoverPrimitive.CloseTrigger asChild {...props}>
      <CloseButton.Root
        ref={ref}
        data-slot="popover-close-icon"
        aria-label={ariaLabel}
        className={clsx(styles.closeIcon, normalizeClassName(className))}
      >
        {children}
      </CloseButton.Root>
    </PopoverPrimitive.CloseTrigger>
  );
});

function PopoverHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-header" className={clsx(styles.header, className)} {...props} />;
}

function PopoverBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-body" className={clsx(styles.body, className)} {...props} />;
}

function PopoverFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="popover-footer" className={clsx(styles.footer, className)} {...props} />;
}

const Popover = Object.assign(PopoverRoot, {
  Root: PopoverRoot,
  RootProvider: PopoverRootProvider,
  Context: PopoverPrimitive.Context,
  Anchor: PopoverAnchor,
  Trigger: PopoverTrigger,
  Indicator: PopoverIndicator,
  Positioner: PopoverPositioner,
  Content: PopoverContent,
  Arrow: PopoverArrow,
  ArrowTip: PopoverArrowTip,
  Title: PopoverTitle,
  Description: PopoverDescription,
  CloseTrigger: PopoverCloseTrigger,
  CloseIcon: PopoverCloseIcon,
  Header: PopoverHeader,
  Body: PopoverBody,
  Footer: PopoverFooter,
});

export { Popover, usePopover, usePopoverContext };

@layer moduix.components {
  .trigger,
  .closeTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--moduix-popover-control-height, var(--moduix-size-md));
    margin: 0;
    padding: var(--moduix-popover-control-padding-y, var(--moduix-spacing-1))
      var(--moduix-popover-control-padding-x, var(--moduix-spacing-3-5));
    border: var(--moduix-popover-control-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-popover-control-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-popover-control-radius, var(--moduix-radius-md));
    background-color: var(--moduix-popover-control-bg, var(--moduix-color-background));
    color: var(--moduix-popover-control-color, var(--moduix-color-foreground));
    font: inherit;
    font-size: var(--moduix-popover-control-font-size, var(--moduix-text-md));
    line-height: var(--moduix-popover-control-line-height, var(--moduix-line-height-text-md));
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--moduix-popover-transition, var(--moduix-transition-default)),
      border-color var(--moduix-popover-transition, var(--moduix-transition-default)),
      color var(--moduix-popover-transition, var(--moduix-transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-popover-control-bg-hover, var(--moduix-color-accent));
      }
    }

    &:active,
    &[data-state='open'] {
      background-color: var(
        --moduix-popover-control-bg-active,
        var(--moduix-popover-control-bg-hover, var(--moduix-color-accent))
      );
    }

    &:focus-visible {
      outline: var(
          --moduix-popover-focus-ring-width,
          var(
            --moduix-popover-control-border-width,
            var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
          )
        )
        solid var(--moduix-popover-focus-ring-color, var(--moduix-color-ring));
      outline-offset: calc(
        var(
            --moduix-popover-focus-ring-width,
            var(
              --moduix-popover-control-border-width,
              var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
            )
          ) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--moduix-popover-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .positioner {
    z-index: var(--z-index, var(--moduix-z-popup));
    max-width: var(--available-width);
    outline: 0;
  }

  .content {
    --moduix-popover-close-icon-size-effective: var(
      --moduix-popover-close-icon-size,
      var(--moduix-spacing-7)
    );
    --moduix-popover-close-icon-offset-effective: var(
      --moduix-popover-close-icon-offset,
      var(--moduix-spacing-3)
    );
    --moduix-popover-header-padding-inline-end-effective: var(
      --moduix-popover-header-padding-inline-end,
      calc(
        var(--moduix-popover-close-icon-size-effective) +
          var(--moduix-popover-close-icon-offset-effective)
      )
    );
    position: relative;
    z-index: calc(var(--moduix-z-popup) + var(--layer-index, 0));
    box-sizing: border-box;
    width: var(--moduix-popover-width, auto);
    height: var(--moduix-popover-height, auto);
    min-width: min(var(--moduix-popover-min-width, 16rem), var(--available-width));
    max-width: min(var(--moduix-popover-max-width, 28rem), var(--available-width));
    max-height: min(var(--moduix-popover-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding: var(--moduix-popover-padding-y, var(--moduix-spacing-4))
      var(--moduix-popover-padding-x, var(--moduix-spacing-4));
    border: 0;
    border-radius: var(--moduix-popover-radius, var(--moduix-radius-md));
    background-color: var(--moduix-popover-bg, var(--moduix-color-popover));
    color: var(--moduix-popover-color, var(--moduix-color-popover-foreground));
    outline: var(--moduix-popover-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-popover-border-color, var(--moduix-color-border));
    box-shadow: var(--moduix-popover-shadow, var(--moduix-shadow-lg));
    transform-origin: var(--transform-origin);

    &[data-state='open'] {
      animation: popover-enter
        var(
          --moduix-popover-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-fast))
            var(--moduix-popup-motion-easing, ease)
        )
        both;
    }

    &[data-state='closed'] {
      animation: popover-exit
        var(
          --moduix-popover-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-fast))
            var(--moduix-popup-motion-easing, ease)
        )
        both;
    }

    &:has(.closeIcon) {
      .header {
        padding-inline-end: var(--moduix-popover-header-padding-inline-end-effective);
      }
    }
  }

  .arrow {
    --arrow-size: var(--moduix-popover-arrow-size, var(--moduix-spacing-2-5));
    --arrow-background: var(--moduix-popover-bg, var(--moduix-color-popover));
  }

  .arrowTip {
    border-top: var(--moduix-popover-border-width, var(--moduix-border-width-sm)) solid
      var(
        --moduix-popover-arrow-stroke-color,
        var(--moduix-popover-border-color, var(--moduix-color-border))
      );
    border-left: var(--moduix-popover-border-width, var(--moduix-border-width-sm)) solid
      var(
        --moduix-popover-arrow-stroke-color,
        var(--moduix-popover-border-color, var(--moduix-color-border))
      );
  }

  .title {
    margin: 0;
    color: var(
      --moduix-popover-title-color,
      var(--moduix-popover-color, var(--moduix-color-popover-foreground))
    );
    font-size: var(--moduix-popover-title-font-size, var(--moduix-text-md));
    font-weight: var(--moduix-popover-title-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-popover-title-line-height, var(--moduix-line-height-text-md));
  }

  .description {
    margin: var(--moduix-popover-description-margin, 0);
    color: var(--moduix-popover-description-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-popover-description-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-popover-description-line-height, var(--moduix-line-height-text-sm));
  }

  .closeIcon {
    --moduix-close-button-size: var(--moduix-popover-close-icon-size-effective);
    --moduix-close-button-radius: var(--moduix-popover-close-icon-radius, var(--moduix-radius-sm));
    --moduix-close-button-icon-size: var(
      --moduix-popover-close-icon-glyph-size,
      var(--moduix-spacing-3-5)
    );
    --moduix-close-button-bg: var(--moduix-popover-close-icon-bg, transparent);
    --moduix-close-button-bg-hover: var(
      --moduix-popover-close-icon-bg-hover,
      var(--moduix-color-accent)
    );
    --moduix-close-button-color: var(
      --moduix-popover-close-icon-color,
      var(--moduix-color-muted-foreground)
    );
    --moduix-close-button-color-hover: var(
      --moduix-popover-close-icon-color-hover,
      var(--moduix-popover-color, var(--moduix-color-popover-foreground))
    );
    --moduix-close-button-focus-ring-color: var(
      --moduix-popover-close-icon-focus-ring-color,
      var(--moduix-color-ring)
    );
    position: absolute;
    inset-block-start: var(--moduix-popover-close-icon-offset-effective);
    inset-inline-end: var(--moduix-popover-close-icon-offset-effective);
  }

  .header {
    display: grid;
    gap: var(--moduix-popover-header-gap, var(--moduix-spacing-1));
  }

  .body {
    margin: var(--moduix-popover-body-margin, 0);
  }

  .footer {
    display: flex;
    align-items: center;
    justify-content: var(--moduix-popover-footer-justify, flex-end);
    gap: var(--moduix-popover-footer-gap, var(--moduix-spacing-2));
    margin: var(--moduix-popover-footer-margin, var(--moduix-spacing-3) 0 0);
  }

  @keyframes popover-enter {
    from {
      opacity: var(
        --moduix-popover-content-starting-opacity,
        var(--moduix-popup-motion-starting-opacity, 0)
      );
      translate: var(
          --moduix-popover-content-starting-translate-x,
          var(--moduix-popup-motion-starting-translate-x, 0)
        )
        var(
          --moduix-popover-content-starting-translate-y,
          var(--moduix-popup-motion-starting-translate-y, 0)
        );
      scale: var(
        --moduix-popover-content-starting-scale,
        var(--moduix-popup-motion-starting-scale, var(--moduix-scale-popup))
      );
    }
  }

  @keyframes popover-exit {
    to {
      opacity: var(
        --moduix-popover-content-ending-opacity,
        var(--moduix-popup-motion-ending-opacity, 0)
      );
      translate: var(
          --moduix-popover-content-ending-translate-x,
          var(--moduix-popup-motion-ending-translate-x, 0)
        )
        var(
          --moduix-popover-content-ending-translate-y,
          var(--moduix-popup-motion-ending-translate-y, 0)
        );
      scale: var(
        --moduix-popover-content-ending-scale,
        var(--moduix-popup-motion-ending-scale, var(--moduix-scale-popup))
      );
    }
  }
}
